    public function parseXmlString(string $xmlString): bool
    {
        $this->errors = [];
        $this->settings = [];
        $this->xml = null;

        // Sanitize the XML string
        $xmlString = $this->sanitizeXmlInput($xmlString);

        if (empty(trim($xmlString))) {
            $this->errors[] = 'XML content is empty.';
