    private function validateUpload(array $uploadedFile): bool
    {
        // Check for upload errors
        if (!isset($uploadedFile['error']) || $uploadedFile['error'] !== UPLOAD_ERR_OK) {
            $errorMessages = [
                UPLOAD_ERR_INI_SIZE => 'File exceeds the upload_max_filesize directive.',
                UPLOAD_ERR_FORM_SIZE => 'File exceeds the MAX_FILE_SIZE directive in the HTML form.',
                UPLOAD_ERR_PARTIAL => 'File was only partially uploaded.',
                UPLOAD_ERR_NO_FILE => 'No file was uploaded.',
                UPLOAD_ERR_NO_TMP_DIR => 'Missing temporary folder.',
                UPLOAD_ERR_CANT_WRITE => 'Failed to write file to disk.',
                UPLOAD_ERR_EXTENSION => 'A PHP extension stopped the file upload.',
            ];
            $errorCode = $uploadedFile['error'] ?? -1;
            $this->errors[] = $errorMessages[$errorCode] ?? 'Unknown upload error (code: ' . $errorCode . ').';
            return false;
        }

        // Verify the file was actually uploaded
        if (!isset($uploadedFile['tmp_name']) || !is_uploaded_file($uploadedFile['tmp_name'])) {
            $this->errors[] = 'Security error: File was not uploaded through HTTP POST.';
            return false;
        }

        // Check file size
        if (isset($uploadedFile['size']) && $uploadedFile['size'] > $this->maxFileSize) {
            $this->errors[] = 'File size exceeds maximum allowed size of ' . $this->formatBytes($this->maxFileSize) . '.';
            return false;
        }

        // Check file extension
        if (isset($uploadedFile['name'])) {
            $extension = strtolower(pathinfo($uploadedFile['name'], PATHINFO_EXTENSION));
            if ($extension !== 'xml') {
                $this->errors[] = 'Invalid file extension. Only .xml files are accepted.';
                return false;
            }
        }

        // Check MIME type
        if (isset($uploadedFile['type'])) {
            $allowedMimeTypes = ['text/xml', 'application/xml', 'application/x-xml'];
            if (!in_array($uploadedFile['type'], $allowedMimeTypes, true)) {
                $this->errors[] = 'Invalid MIME type. Expected XML content type.';
                return false;
            }
        }

        return true;
