    /**
     * Sanitize XML input to prevent XXE and other injection attacks
     *
     * @param string $xmlString
     * @return string
     */
    private function sanitizeXmlInput(string $xmlString): string
    {
        // Remove any DOCTYPE declarations to prevent XXE
        $xmlString = preg_replace('/<!DOCTYPE[^>]*>/i', '', $xmlString);

        // Remove any ENTITY declarations
        $xmlString = preg_replace('/<!ENTITY[^>]*>/i', '', $xmlString);

        // Remove any SYSTEM or PUBLIC references
        $xmlString = preg_replace('/SYSTEM\s+"[^"]*"/i', '', $xmlString);
        $xmlString = preg_replace('/PUBLIC\s+"[^"]*"\s+"[^"]*"/i', '', $xmlString);

        return $xmlString;
    }

    /**
     * Validate the root element of the XML
     *
     * @return bool
     */
    private function validateRootElement(): bool
    {
        if ($this->xml === null) {
            $this->errors[] = 'XML document is null.';
            return false;
        }

        $rootName = $this->xml->getName();
        if (!in_array($rootName, $this->allowedRootElements, true)) {
            $this->errors[] = 'Invalid root element "' . htmlspecialchars($rootName) . '". Allowed: ' . implode(', ', $this->allowedRootElements) . '.';
            return false;
        }

        return true;
    }

    /**
     * Recursively extract settings from the XML element
     *
     * @param SimpleXMLElement $element
     * @param string $prefix Key prefix for nested elements
     * @param int $depth Current recursion depth
     * @return array
     */
    private function extractSettings(SimpleXMLElement $element, string $prefix = '', int $depth = 0): array
    {
        $settings = [];
        $maxDepth = 10; // Prevent excessive nesting

        if ($depth > $maxDepth) {
            $this->errors[] = 'XML nesting exceeds maximum depth of ' . $maxDepth . '.';
            return $settings;
        }

        // Extract attributes of the current element
        foreach ($element->attributes() as $attrName => $attrValue) {
            $key = $prefix ? $prefix . '.' . '@' . (string)$attrName : '@' . (string)$attrName;
            $settings[$key] = $this->sanitizeValue((string)$attrValue);
        }

        // Process child elements
        $childCounts = [];
        foreach ($element->children() as $child) {
            $childName = $child->getName();
            if (!isset($childCounts[$childName])) {
                $childCounts[$childName] = 0;
            }
            $childCounts[$childName]++;
        }

        $childIndices = [];
        foreach ($element->children() as $child) {
            $childName = $child->getName();
            $key = $prefix ? $prefix . '.' . $childName : $childName;

            // Handle elements with 'key' and 'value' attributes (common config pattern)
            if ($this->isKeyValuePair($child)) {
                $kvKey = (string)$child['key'];
                $kvValue = (string)$child['value'];
                $settingKey = $prefix ? $prefix . '.' . $kvKey : $kvKey;
                $settings[$settingKey] = $this->sanitizeValue($kvValue);
                continue;
            }

            // Handle elements with 'name' and 'value' attributes
            if ($this->isNameValuePair($child)) {
                $nvName = (string)$child['name'];
                $nvValue = (string)$child['value'];
                $settingKey = $prefix ? $prefix . '.' . $nvName : $nvName;
                $settings[$settingKey] = $this->sanitizeValue($nvValue);
                continue;
            }

            // Handle repeated elements (arrays)
            if ($childCounts[$childName] > 1) {
                if (!isset($childIndices[$childName])) {
                    $childIndices[$childName] = 0;
                }
                $indexedKey = $key . '[' . $childIndices[$childName] . ']';
                $childIndices[$childName]++;

                if ($child->count() > 0) {
                    $nestedSettings = $this->extractSettings($child, $indexedKey, $depth + 1);
                    $settings = array_merge($settings, $nestedSettings);
                } else {
                    $settings[$indexedKey] = $this->sanitizeValue((string)$child);
                    // Also extract attributes
                    foreach ($child->attributes() as $attrName => $attrValue) {
                        $attrKey = $indexedKey . '.@' . (string)$attrName;
                        $settings[$attrKey] = $this->sanitizeValue((string)$attrValue);
                    }
                }
                continue;
            }

            // Handle elements with children (nested sections)
            if ($child->count() > 0) {
                $nestedSettings = $this->extractSettings($child, $key, $depth + 1);
                $settings = array_merge($settings, $nestedSettings);
            } else {
                // Leaf element - extract value
                $value = trim((string)$child);
                $settings[$key] = $this->sanitizeValue($value);

                // Also extract attributes of leaf elements
                foreach ($child->attributes() as $attrName => $attrValue) {
                    $attrKey = $key . '.@' . (string)$attrName;
                    $settings[$attrKey] = $this->sanitizeValue((string)$attrValue);
                }
            }
        }

        return $settings;
    }

    /**
     * Check if an element is a key-value pair (<add key="..." value="..." />)
     *
     * @param SimpleXMLElement $element
     * @return bool
     */
    private function isKeyValuePair(SimpleXMLElement $element): bool
    {
        return isset($element['key']) && isset($element['value']);
    }

    /**
     * Check if an element is a name-value pair (<setting name="..." value="..." />)
     *
     * @param SimpleXMLElement $element
     * @return bool
     */
    private function isNameValuePair(SimpleXMLElement $element): bool
    {
        return isset($element['name']) && isset($element['value']);
    }

    /**
     * Sanitize a configuration value
     *
     * @param string $value
