    /**
     * Get a specific setting by its dot-notation key
     *
     * @param string $key
     * @param mixed $default
     * @return mixed
     */
    public function getSetting(string $key, mixed $default = null): mixed
    {
        return $this->settings[$key] ?? $default;
    }

    /**
     * Get settings for a specific section (prefix)
     *
     * @param string $section
     * @return array
     */
    public function getSection(string $section): array
    {
        $sectionSettings = [];
        $sectionPrefix = $section . '.';

        foreach ($this->settings as $key => $value) {
            if (str_starts_with($key, $sectionPrefix)) {
                $subKey = substr($key, strlen($sectionPrefix));
                $sectionSettings[$subKey] = $value;
            }
        }

        return $sectionSettings;
    }

    /**
     * Get all section names (top-level keys)
     *
     * @return array
     */
    public function getSections(): array
    {
        $sections = [];
        foreach (array_keys($this->settings) as $key) {
            $parts = explode('.', $key);
            if (count($parts) > 1 && !str_starts_with($parts[0], '@')) {
                $sections[$parts[0]] = true;
            }
        }
        return array_keys($sections);
    }

    /**
     * Check if a setting exists
     *
     * @param string $key
     * @return bool
     */
    public function hasSetting(string $key): bool
    {
        return array_key_exists($key, $this->settings);
    }

    /**
     * Get the settings as a nested associative array
     *
     * @return array
     */
    public function getNestedSettings(): array
    {
        $nested = [];

        foreach ($this->settings as $key => $value) {
            $keys = explode('.', $key);
            $current = &$nested;

            foreach ($keys as $i => $part) {
                if ($i === count($keys) - 1) {
                    $current[$part] = $value;
                } else {
                    if (!isset($current[$part]) || !is_array($current[$part])) {
                        $current[$part] = [];
                    }
                    $current = &$current[$part];
                }
            }
            unset($current);
        }

        return $nested;
    }

    /**
     * Export settings to JSON format
     *
     * @param bool $nested Whether to export as nested structure
     * @return string
     */
    public function toJson(bool $nested = false): string
    {
        $data = $nested ? $this->getNestedSettings() : $this->settings;
        return json_encode($data, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
    }

    /**
