    /**
     * Validate settings against a schema definition
     *
     * @param array $schema Associative array of key => ['type' => string, 'required' => bool, 'pattern' => string]
     * @return array Validation errors
     */
    public function validateAgainstSchema(array $schema): array
    {
        $validationErrors = [];

        foreach ($schema as $key => $rules) {
            $isRequired = $rules['required'] ?? false;
            $expectedType = $rules['type'] ?? 'string';
            $pattern = $rules['pattern'] ?? null;
            $allowedValues = $rules['allowed_values'] ?? null;

            // Check required fields
            if ($isRequired && !$this->hasSetting($key)) {
                $validationErrors[] = "Required setting '{$key}' is missing.";
                continue;
            }

            if (!$this->hasSetting($key)) {
                continue;
            }

            $value = $this->getSetting($key);

            // Type validation
            switch ($expectedType) {
                case 'integer':
                case 'int':
                    if (!ctype_digit(str_replace('-', '', $value))) {
                        $validationErrors[] = "Setting '{$key}' must be an integer.";
                    }
                    break;
                case 'float':
                case 'double':
                case 'number':
                    if (!is_numeric($value)) {
                        $validationErrors[] = "Setting '{$key}' must be a number.";
                    }
                    break;
                case 'boolean':
                case 'bool':
                    $boolValues = ['true', 'false', '1', '0', 'yes', 'no', 'on', 'off'];
                    if (!in_array(strtolower($value), $boolValues, true)) {
                        $validationErrors[] = "Setting '{$key}' must be a boolean value.";
                    }
                    break;
                case 'email':
                    $decodedValue = htmlspecialchars_decode($value, ENT_QUOTES);
                    if (!filter_var($decodedValue, FILTER_VALIDATE_EMAIL)) {
                        $validationErrors[] = "Setting '{$key}' must be a valid email address.";
                    }
                    break;
                case 'url':
                    $decodedValue = htmlspecialchars_decode($value, ENT_QUOTES);
                    if (!filter_var($decodedValue, FILTER_VALIDATE_URL)) {
                        $validationErrors[] = "Setting '{$key}' must be a valid URL.";
                    }
                    break;
                case 'string':
                default:
                    // String type - no special validation needed
                    break;
            }

            // Pattern validation
            if ($pattern !== null && !preg_match($pattern, $value)) {
                $validationErrors[] = "Setting '{$key}' does not match the required pattern.";
            }

            // Allowed values validation
            if ($allowedValues !== null && !in_array($value, $allowedValues, true)) {
                $validationErrors[] = "Setting '{$key}' must be one of: " . implode(', ', $allowedValues) . ".";
            }
        }

        return $validationErrors;
    }

    /**
     * Format bytes to human-readable string
     *
     * @param int $bytes
     * @return string
     */
    private function formatBytes(int $bytes): string
    {
        $units = ['B', 'KB', 'MB', 'GB'];
        $factor = floor((strlen((string)$bytes) - 1) / 3);
        return sprintf("%.2f %s", $bytes / pow(1024, $factor), $units[$factor] ?? 'TB');
    }
}


