/*
 * Example 1: Parse XML from an uploaded file
 */
function handleConfigUpload(): void
{
    if ($_SERVER['REQUEST_METHOD'] !== 'POST' || !isset($_FILES['config_file'])) {
        echo "No file uploaded.";
        return;
    }

    $parser = new XmlConfigParser(
        maxFileSize: 2097152, // 2MB
        allowedRootElements: ['configuration', 'config', 'settings', 'appSettings']
    );

    if ($parser->processUploadedFile($_FILES['config_file'])) {
        echo "Configuration parsed successfully!\n\n";

        // Get all settings
        $settings = $parser->getSettings();
        echo "All Settings:\n";
        print_r($settings);

        // Get a specific setting
        $dbHost = $parser->getSetting('database.host', 'localhost');
        echo "\nDatabase Host: {$dbHost}\n";

        // Get a section
        $dbSettings = $parser->getSection('database');
        echo "\nDatabase Section:\n";
        print_r($dbSettings);

        // Export as JSON
        echo "\nJSON Output:\n";
        echo $parser->toJson(nested: true);
    } else {
        echo "Failed to parse configuration:\n";
        foreach ($parser->getErrors() as $error) {
            echo "  - {$error}\n";
        }
    }
}


/*
 * Example 2: Parse XML from a string with schema validation
 */
function parseConfigString(): void
{
    $xmlContent = <<<XML
<?xml version="1.0" encoding="UTF-8"?>
<configuration>
    <appInfo>
        <name>Enterprise App</name>
        <version>2.5.1</version>
        <environment>production</environment>
    </appInfo>
    
    <database>
        <host>db.example.com</host>
        <port>5432</port>
        <name>enterprise_db</name>
        <username>app_user</username>
        <password>s3cur3P@ss!</password>
        <pool>
            <minConnections>5</minConnections>
            <maxConnections>50</maxConnections>
            <timeout>30</timeout>
        </pool>
    </database>
    
    <cache>
        <enabled>true</enabled>
        <driver>redis</driver>
        <ttl>3600</ttl>
        <add key="redis.host" value="cache.example.com" />
        <add key="redis.port" value="6379" />
    </cache>
    
    <logging>
        <level>info</level>
        <output>file</output>
        <path>/var/log/app/enterprise.log</path>
        <rotation enabled="true" maxSize="100MB" keepFiles="10" />
    </logging>
    
    <security>
        <encryption algorithm="AES-256-GCM">enabled</encryption>
        <cors>
            <allowedOrigin>https://app.example.com</allowedOrigin>
            <allowedOrigin>https://admin.example.com</allowedOrigin>
        </cors>
        <rateLimit>
            <setting name="maxRequests" value="1000" />
            <setting name="windowSeconds" value="60" />
        </rateLimit>
    </security>
    
    <features>
        <feature name="dark_mode" value="true" />
        <feature name="beta_features" value="false" />
        <feature name="max_upload_size" value="10485760" />
    </features>
</configuration>
XML;

    $parser = new XmlConfigParser();

    if ($parser->parseXmlString($xmlContent)) {
        echo "=== All Flat Settings ===\n";
        foreach ($parser->getSettings() as $key => $value) {
            echo "  {$key} = {$value}\n";
        }

        echo "\n=== Sections ===\n";
        foreach ($parser->getSections() as $section) {
            echo "  - {$section}\n";
        }

        echo "\n=== Database Section ===\n";
        $dbSection = $parser->getSection('database');
        print_r($dbSection);

        echo "\n=== Specific Settings ===\n";
        echo "App Name: " . $parser->getSetting('appInfo.name') . "\n";
        echo "DB Host: " . $parser->getSetting('database.host') . "\n";
        echo "Cache TTL: " . $parser->getSetting('cache.ttl') . "\n";
        echo "Log Level: " . $parser->getSetting('logging.level') . "\n";
        echo "Redis Host: " . $parser->getSetting('cache.redis.host') . "\n";

        // Schema validation
        $schema = [
            'database.host' => ['type' => 'string', 'required' => true],
            'database.port' => ['type' => 'integer', 'required' => true],
            'cache.enabled' => ['type' => 'boolean', 'required' => true],
            'cache.ttl' => ['type' => 'integer', 'required' => true],
            'logging.level' => [
                'type' => 'string',
                'required' => true,
                'allowed_values' => ['debug', 'info', 'warning', 'error', 'critical']
            ],
            'appInfo.environment' => [
                'type' => 'string',
                'required' => true,
                'allowed_values' => ['development', 'staging', 'production']
            ],
        ];

        echo "\n=== Schema Validation ===\n";
        $validationErrors = $parser->validateAgainstSchema($schema);
        if (empty($validationErrors)) {
            echo "All settings are valid!\n";
        } else {
            foreach ($validationErrors as $error) {
                echo "  Validation Error: {$error}\n";
            }
        }

        echo "\n=== Nested JSON Output ===\n";
        echo $parser->toJson(nested: true) . "\n";

    } else {
        echo "Parsing failed:\n";
        foreach ($parser->getErrors() as $error) {
            echo "  - {$error}\n";
        }
    }
}

